answer_code:
import java.util.Scanner;

class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int[] cnt = new int[26];
        for (char c : s.toCharArray()) cnt[c - 'a']++;
        int best = 0;
        for (int i = 1; i < 26; i++) {
            if (cnt[i] > cnt[best]) best = i;
        }
        System.out.println((char) ('a' + best));
    }
}
